module pulse_generator (
    input clk,
    input reset,
    output reg pulse
);

    reg [1:0] count;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset) begin
            count <= 0;
            pulse <= 0;
        end else if (count == 2) begin
            pulse <= 1;
            count <= 0;
        end else begin
            count <= count + 1;
            pulse <= 0;
        end
    end
endmodule
